/**
 * PM Formula Multi-Render Widget
 * ==============================
 *
 * Adds a tab strip (LaTeX | HTML | SVG | MathML | Plain) to every formula
 * card on the page. Each tab lazy-loads the corresponding render from
 * AutoGenerated/formula_renders.json — a precomputed bundle produced by
 * `metaphysica.generators.generate_formula_renders`.
 *
 * Design:
 *   - One global JSON fetch on first interaction (cached).
 *   - Default tab is LaTeX (matches existing behaviour — no UX regression
 *     when the JSON is absent).
 *   - A page-header pill lets the reader pick a default format that
 *     propagates to every card on the page.
 *   - Lazy: the actual render string isn't injected until the tab is
 *     clicked or the page-default changes.
 *
 * Graceful degradation:
 *   - If formula_renders.json is missing, no tab strip is attached and
 *     the existing inline LaTeX/Flow display stays intact.
 *   - If a specific format is missing for a formula, the tab is hidden.
 *
 * Public API:
 *   PMFormulaMultiRender.attachAll(rootEl)
 *       Walks every .formula-card under rootEl, attaches a tab strip.
 *   PMFormulaMultiRender.setDefaultFormat(fmt)
 *       Propagates a chosen format to every card on the page.
 *   PMFormulaMultiRender.getDefaultFormat() -> string
 *
 * Copyright (c) 2025-2026 Andrew Keith Watts. All rights reserved.
 */
(function (window) {
    'use strict';

    const RENDERS_URL = '/AutoGenerated/formula_renders.json';
    const RENDERS_URL_REL = '../AutoGenerated/formula_renders.json';
    const STORAGE_KEY = 'pm-formula-default-format';
    const FORMAT_LABELS = {
        latex: 'LaTeX',
        html: 'HTML',
        svg: 'SVG',
        mathml: 'MathML',
        png: 'PNG',
        pdf: 'PDF',
        plain: 'Plain',
    };
    // Order used for tab strip when no explicit order is given.
    const PREFERRED_ORDER = ['latex', 'html', 'svg', 'mathml', 'png', 'pdf', 'plain'];

    let _rendersPromise = null;
    let _rendersCache = null;
    let _defaultFormat = (function () {
        try {
            return window.localStorage.getItem(STORAGE_KEY) || 'latex';
        } catch (e) {
            return 'latex';
        }
    })();

    /** Lazily fetch and parse formula_renders.json. */
    function loadRenders() {
        if (_rendersCache) return Promise.resolve(_rendersCache);
        if (_rendersPromise) return _rendersPromise;

        const tryFetch = (url) => fetch(url, { cache: 'force-cache' })
            .then((r) => (r && r.ok ? r.json() : null));

        _rendersPromise = tryFetch(RENDERS_URL)
            .catch(() => null)
            .then((data) => data || tryFetch(RENDERS_URL_REL).catch(() => null))
            .then((data) => {
                if (!data || !data.f) {
                    console.info('[PMFormulaMultiRender] formula_renders.json absent — multi-format tabs disabled.');
                    _rendersCache = { _v: 0, _formats: [], f: {} };
                } else {
                    _rendersCache = data;
                    console.info(`[PMFormulaMultiRender] Loaded ${Object.keys(data.f).length} formula renders, formats: ${data._formats.join(', ')}`);
                }
                return _rendersCache;
            });
        return _rendersPromise;
    }

    /** Extract formula id from a card element (id is `formula-<id>`). */
    function cardFormulaId(card) {
        const raw = card.id || '';
        return raw.startsWith('formula-') ? raw.slice('formula-'.length) : raw;
    }

    function getAvailableFormats(entry) {
        if (!entry) return [];
        return PREFERRED_ORDER.filter((fmt) => Object.prototype.hasOwnProperty.call(entry, fmt));
    }

    function buildTabStrip(card, entry) {
        const formats = getAvailableFormats(entry);
        if (formats.length === 0) return null;

        const wrap = document.createElement('div');
        wrap.className = 'pm-multi-render';
        wrap.style.cssText = 'margin: 1rem 0; border: 1px solid rgba(139, 127, 255, 0.18); border-radius: 10px; background: rgba(17, 20, 38, 0.5); overflow: hidden;';

        const strip = document.createElement('div');
        strip.className = 'pm-multi-render-tabs';
        strip.style.cssText = 'display: flex; flex-wrap: wrap; gap: 0; border-bottom: 1px solid rgba(139, 127, 255, 0.18); background: rgba(11, 14, 26, 0.7);';

        formats.forEach((fmt) => {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'pm-multi-render-tab';
            btn.dataset.format = fmt;
            btn.textContent = FORMAT_LABELS[fmt] || fmt;
            btn.style.cssText = 'background: transparent; border: none; padding: 0.5rem 0.9rem; color: var(--text-muted, #9aa); font-size: 0.85rem; cursor: pointer; border-right: 1px solid rgba(139, 127, 255, 0.1); transition: color 0.15s, background 0.15s;';
            btn.addEventListener('click', (e) => {
                e.preventDefault();
                showFormat(wrap, entry, fmt);
            });
            strip.appendChild(btn);
        });

        const body = document.createElement('div');
        body.className = 'pm-multi-render-body';
        body.style.cssText = 'padding: 1rem; min-height: 60px; overflow-x: auto; color: var(--text-primary, #ddd);';
        body.innerHTML = '<div class="pm-multi-render-empty" style="color: var(--text-muted, #999); font-size: 0.85rem;">Pick a format above.</div>';

        wrap.appendChild(strip);
        wrap.appendChild(body);

        // Auto-show the current default format if available.
        const initial = formats.includes(_defaultFormat) ? _defaultFormat : formats[0];
        showFormat(wrap, entry, initial);

        return wrap;
    }

    function showFormat(wrap, entry, fmt) {
        const body = wrap.querySelector('.pm-multi-render-body');
        const tabs = wrap.querySelectorAll('.pm-multi-render-tab');
        tabs.forEach((t) => {
            const active = t.dataset.format === fmt;
            t.style.color = active ? 'var(--accent-primary, #8b7fff)' : 'var(--text-muted, #9aa)';
            t.style.background = active ? 'rgba(139, 127, 255, 0.12)' : 'transparent';
            t.style.fontWeight = active ? '600' : '400';
            t.setAttribute('aria-selected', active ? 'true' : 'false');
        });
        if (!body) return;
        const payload = entry[fmt];
        if (payload === undefined) {
            body.innerHTML = `<div class="pm-multi-render-missing" style="color: var(--text-muted, #999); font-size: 0.85rem;">No ${FORMAT_LABELS[fmt] || fmt} render available for this formula.</div>`;
            return;
        }
        body.innerHTML = formatBody(fmt, payload);
        // Trigger MathJax re-typeset if this is a math format.
        if ((fmt === 'latex' || fmt === 'mathml') && window.MathJax && window.MathJax.typesetPromise) {
            try {
                window.MathJax.typesetPromise([body]).catch(() => {});
            } catch (e) { /* ignore */ }
        }
    }

    function escapeHtml(s) {
        return String(s).replace(/[&<>"']/g, (c) => ({
            '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;',
        })[c]);
    }

    function formatBody(fmt, payload) {
        switch (fmt) {
            case 'latex':
                // MathJax-style delimiter.
                return `<div class="pm-render-latex" style="font-size: 1.1rem; text-align: center;">$$${payload}$$</div>`;
            case 'html':
            case 'svg':
                // Trust EML-Math output — it's locally generated.
                return `<div class="pm-render-${fmt}" style="overflow-x: auto;">${payload}</div>`;
            case 'mathml':
                return `<div class="pm-render-mathml" style="text-align: center;">${payload}</div>`;
            case 'png':
            case 'pdf':
                // PNG: embed as img. PDF: provide a download link.
                if (fmt === 'png') {
                    return `<div class="pm-render-png" style="text-align: center;"><img alt="formula PNG render" src="${payload}" style="max-width: 100%; height: auto;"></div>`;
                }
                return `<div class="pm-render-pdf"><a href="${payload}" download="formula.pdf" style="color: var(--accent-primary, #8b7fff);">Download PDF render</a></div>`;
            case 'plain':
            default:
                return `<pre class="pm-render-plain" style="margin: 0; font-family: 'Fira Code', 'Courier New', monospace; font-size: 0.85rem; color: var(--text-secondary, #bbb); white-space: pre-wrap; word-break: break-all;"><code>${escapeHtml(payload)}</code></pre>`;
        }
    }

    function attachToCard(card, renders) {
        if (!card || card.dataset.pmMultiRenderAttached === 'true') return;
        const fid = cardFormulaId(card);
        if (!fid) return;
        const entry = renders.f[fid];
        if (!entry) return;
        const strip = buildTabStrip(card, entry);
        if (!strip) return;

        // Insertion point: right after the main formula-display interactive
        // block. Fall back to appending at end of card.
        const interactive = card.querySelector('.interactive-formula') || card;
        if (interactive.parentNode === card) {
            interactive.insertAdjacentElement('afterend', strip);
        } else {
            card.appendChild(strip);
        }
        card.dataset.pmMultiRenderAttached = 'true';
    }

    function attachAll(rootEl) {
        const root = rootEl || document;
        loadRenders().then((renders) => {
            if (!renders || !renders.f || Object.keys(renders.f).length === 0) return;
            const cards = root.querySelectorAll('.formula-card');
            cards.forEach((c) => attachToCard(c, renders));
        });
    }

    function setDefaultFormat(fmt) {
        if (!fmt) return;
        _defaultFormat = fmt;
        try { window.localStorage.setItem(STORAGE_KEY, fmt); } catch (e) { /* ignore */ }
        // Propagate to every attached card.
        document.querySelectorAll('.pm-multi-render').forEach((wrap) => {
            const tab = wrap.querySelector(`.pm-multi-render-tab[data-format="${fmt}"]`);
            if (tab) tab.click();
        });
    }

    function getDefaultFormat() { return _defaultFormat; }

    /**
     * Watch the formula container for re-renders (the main page rebuilds
     * the formula list when filters change). When new .formula-card nodes
     * appear, attach the tab strip to each.
     */
    function startAutoAttach(rootEl) {
        const root = rootEl || document.body;
        attachAll(root);
        if (!('MutationObserver' in window)) return;
        const obs = new MutationObserver((muts) => {
            let touched = false;
            for (const m of muts) {
                for (const node of m.addedNodes) {
                    if (!(node instanceof Element)) continue;
                    if (node.classList && node.classList.contains('formula-card')) {
                        touched = true;
                    } else if (node.querySelector && node.querySelector('.formula-card')) {
                        touched = true;
                    }
                }
            }
            if (touched) attachAll(root);
        });
        obs.observe(root, { childList: true, subtree: true });
    }

    window.PMFormulaMultiRender = {
        attachAll,
        setDefaultFormat,
        getDefaultFormat,
        startAutoAttach,
        loadRenders,
    };

    // Auto-bootstrap on DOMContentLoaded so card consumers don't need
    // to manually wire anything.
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', () => startAutoAttach());
    } else {
        startAutoAttach();
    }

    console.log('[PM] Formula multi-render widget initialised');
})(typeof window !== 'undefined' ? window : globalThis);
